// app/lib/auth.ts
import type { NextAuthOptions } from "next-auth";
import Credentials from "next-auth/providers/credentials";

export const authOptions: NextAuthOptions = {
  session: { strategy: "jwt" },
  providers: [
    Credentials({
      name: "Credentials",
      credentials: {
        username: { label: "Username", type: "text" },
        password: { label: "Password", type: "password" },
      },
      async authorize(credentials) {
        if (!credentials) return null;
        
        // ข้อมูลจำลองสำหรับล็อกอิน (Mock Accounts) 
        // app/lib/auth.ts
const accounts = [
  { 
    id: "1", 
    name: "User Patient", 
    email: "user@meditap.com", 
    role: "user", 
    username: "demo", 
    password: "123" 
  }
];

        const found = accounts.find(
          (a) => a.username === credentials.username && a.password === credentials.password
        );

        if (!found) return null;
        return { id: found.id, name: found.name, email: found.email, role: found.role as any };
      },
    }),
  ],
  callbacks: {
    async jwt({ token, user }) {
      if (user) {
        token.id = (user as any).id;
        token.role = (user as any).role;
      }
      return token;
    },
    async session({ session, token }) {
      if (session.user) {
        (session.user as any).id = token.id;
        (session.user as any).role = token.role;
      }
      return session;
    },
  },
  pages: { signIn: "/login" },
};